#define BILLION                                 1000000000
static unsigned long long get_perf_count()
{
    struct timespec ts;
    clock_gettime(CLOCK_MONOTONIC, &ts);
    return (unsigned long long)((unsigned long long)ts.tv_nsec + (unsigned long long)ts.tv_sec * BILLION);
}

void ExportWAV(
        const std::string & Filename,
		const std::vector<float>& Data,
		unsigned SampleRate) {
    AudioFile<float>::AudioBuffer Buffer;
	Buffer.resize(1);

	Buffer[0] = Data;
	size_t BufSz = Data.size();

	AudioFile<float> File;
	File.setAudioBuffer(Buffer);
	File.setAudioBufferSize(1, (int)BufSz);
	File.setNumSamplesPerChannel((int)BufSz);
	File.setNumChannels(1);
	File.setBitDepth(16);
	File.setSampleRate(SAMEPLERATE);
	File.save(Filename, AudioFileFormat::Wave);
}

void __calc_mag_phase(vector<cpx_type> fft_res, float* in_mag, float* in_phase, int count)
{
    for (int i = 0; i < count; i++)
	{
        in_mag[i] = sqrtf(fft_res[i].real() * fft_res[i].real() + fft_res[i].imag() * fft_res[i].imag());
        in_phase[i] = atan2f(fft_res[i].imag(), fft_res[i].real());
    }
}

void tflite_create(trg_engine* engine)
{
    //---------------------------------------------
    engine->model1 = TfLiteModelCreateFromFile(DTLN_MODEL_A);
    if (engine->model1 == NULL)
    {
        printf("load model1 fail\n");
        return;
    }

    // Build the interpreter
    TfLiteInterpreterOptions* options = TfLiteInterpreterOptionsCreate();
    TfLiteInterpreterOptionsSetNumThreads(options, 1);

    // Create the interpreter.
    engine->interpreter_1 = TfLiteInterpreterCreate(engine->model1, options);
    if (engine->interpreter_1 == nullptr) {
        printf("Failed to create interpreter");
        return;
    }

    // Allocate tensor buffers.
    if (TfLiteInterpreterAllocateTensors(engine->interpreter_1) != kTfLiteOk) {
        printf("Failed to allocate tensors!");
        return;
    }

    //---------------------------------------------
    engine->model2 = TfLiteModelCreateFromFile(DTLN_MODEL_B);
    if (engine->model2 == NULL)
    {
        printf("load model2 fail\n");
        return;
    }

    // Create the interpreter.
    engine->interpreter_2 = TfLiteInterpreterCreate(engine->model2, options);
    if (engine->interpreter_2 == nullptr) {
        printf("Failed to create interpreter");
        return;
    }

    // Allocate tensor buffers.
    if (TfLiteInterpreterAllocateTensors(engine->interpreter_2) != kTfLiteOk) {
        printf("Failed to allocate tensors!");
        return;
    }

    ////////////////////////////////////

    engine->input_details_1[0] = TfLiteInterpreterGetInputTensor(engine->interpreter_1, 0);
    engine->input_details_1[1] = TfLiteInterpreterGetInputTensor(engine->interpreter_1, 1);
	engine->input_details_1[2] = TfLiteInterpreterGetInputTensor(engine->interpreter_1, 2);
    engine->output_details_1[0] = TfLiteInterpreterGetOutputTensor(engine->interpreter_1, 0);
    engine->output_details_1[1] = TfLiteInterpreterGetOutputTensor(engine->interpreter_1, 1);

    engine->input_details_2[0] = TfLiteInterpreterGetInputTensor(engine->interpreter_2, 0);
    engine->input_details_2[1] = TfLiteInterpreterGetInputTensor(engine->interpreter_2, 1);
	engine->input_details_2[2] = TfLiteInterpreterGetInputTensor(engine->interpreter_2, 2);
    engine->output_details_2[0] = TfLiteInterpreterGetOutputTensor(engine->interpreter_2, 0);
    engine->output_details_2[1] = TfLiteInterpreterGetOutputTensor(engine->interpreter_2, 1);
	printf("tflite_create ok\n");
}

void tflite_destroy(trg_engine* engine)
{
    TfLiteModelDelete(engine->model1);
    TfLiteModelDelete(engine->model2);
}


void tflite_infer(trg_engine* m_pEngine)
{
    int i;
	float mic_mag[FFT_OUT_SIZE] ={0}; ;
    float mic_phase[FFT_OUT_SIZE] = { 0 };
    float lpb_mag[FFT_OUT_SIZE]={0};
    float lpb_phase[FFT_OUT_SIZE]={0};

	float estimated_block[DTLN_BLOCK_LEN] ={0};

    float fft_mic[DTLN_BLOCK_LEN];
    std::vector<cpx_type> fft_res(DTLN_BLOCK_LEN);
    float lpb_in[DTLN_BLOCK_LEN];
    std::vector<cpx_type> lpb_res(DTLN_BLOCK_LEN);

    std::vector<size_t> shape;
    shape.push_back(DTLN_BLOCK_LEN);
    std::vector<size_t> axes;
    axes.push_back(0);
    std::vector<ptrdiff_t> stridel, strideo;
    strideo.push_back(sizeof(cpx_type));
    stridel.push_back(sizeof(float));
    for (i = 0; i < DTLN_BLOCK_LEN; i++){
        fft_mic[i] = m_pEngine->mic_buffer[i];
		lpb_in[i]= m_pEngine->lpb_buffer[i];
	}

    //apply FFT to input wav data
    pocketfft::r2c(shape, stridel, strideo, axes, pocketfft::FORWARD, fft_mic, fft_res.data(), (float)1.0);
	__calc_mag_phase(fft_res, mic_mag, mic_phase, FFT_OUT_SIZE);
    pocketfft::r2c(shape, stridel, strideo, axes, pocketfft::FORWARD, lpb_in,lpb_res.data(), (float)1.0);
	__calc_mag_phase(lpb_res, lpb_mag, lpb_phase, FFT_OUT_SIZE);

    memcpy(m_pEngine->input_details_1[0]->data.f, mic_mag, FFT_OUT_SIZE * sizeof(float));
	memcpy(m_pEngine->input_details_1[1]->data.f, lpb_mag, FFT_OUT_SIZE * sizeof(float));
    memcpy(m_pEngine->input_details_1[2]->data.f, m_pEngine->states_a, DTLN_STATE_SIZE * sizeof(float));

    if (TfLiteInterpreterInvoke(m_pEngine->interpreter_1) != kTfLiteOk) {
        printf("Error invoking detection model");
    }

    float* out_mask = m_pEngine->output_details_1[0]->data.f;
    memcpy(m_pEngine->states_a, m_pEngine->output_details_1[1]->data.f, DTLN_STATE_SIZE * sizeof(float));
	for (i = 0; i < FFT_OUT_SIZE; i++) {
        fft_res[i] = cpx_type(mic_mag[i] * out_mask[i] * cosf(mic_phase[i]),
						mic_mag[i] * out_mask[i] * sinf(mic_phase[i]));
	}

    pocketfft::c2r(shape, strideo, stridel, axes, pocketfft::BACKWARD, fft_res.data(), fft_mic, (float)1.0);

    for (i = 0; i < DTLN_BLOCK_LEN; i++)
        estimated_block[i] = fft_mic[i] / DTLN_BLOCK_LEN;

    memcpy(m_pEngine->input_details_2[0]->data.f, estimated_block, DTLN_BLOCK_LEN * sizeof(float));
	memcpy(m_pEngine->input_details_2[1]->data.f, m_pEngine->lpb_buffer, DTLN_BLOCK_LEN * sizeof(float));
    memcpy(m_pEngine->input_details_2[2]->data.f, m_pEngine->states_b, DTLN_STATE_SIZE * sizeof(float));
    if (TfLiteInterpreterInvoke(m_pEngine->interpreter_2) != kTfLiteOk) {
        printf("Error invoking detection model");
    }

    float* out_block = m_pEngine->output_details_2[0]->data.f;
    memcpy(m_pEngine->states_b, m_pEngine->output_details_2[1]->data.f, DTLN_STATE_SIZE * sizeof(float));

    //apply overlap_add
    memmove(m_pEngine->out_buffer, m_pEngine->out_buffer + DTLN_BLOCK_SHIFT, (DTLN_BLOCK_LEN - DTLN_BLOCK_SHIFT) * sizeof(float));
    memset(m_pEngine->out_buffer + (DTLN_BLOCK_LEN - DTLN_BLOCK_SHIFT), 0, DTLN_BLOCK_SHIFT * sizeof(float));
    for (i = 0; i < DTLN_BLOCK_LEN; i++)
        m_pEngine->out_buffer[i] += out_block[i];
}

