int mymain22(int argc,char **argv)
{
    if(argc != 4)
    {
        printf("usage: %s <micfile> <lpbfile> <outputfile>\n",argv[0]);
        return 0;
    }

    trg_engine eng1;
    tflite_create(&eng1);

    std::vector<float>  testaecdata; //vector used to store enhanced data in a wav file
    AudioFile<float> inputmicfile;
    AudioFile<float> inputlpbfile;
    std::string micfile=argv[1];
    std::string lpbfile=argv[2];
    inputmicfile.load(micfile);
    inputlpbfile.load(lpbfile);
    int audiolen=inputmicfile.getNumSamplesPerChannel();
    int process_num=(audiolen-DTLN_BLOCK_LEN)/DTLN_BLOCK_SHIFT;

    printf("process_num=%d\n",process_num);
    for(int i=0;i<process_num;i++)
    {
        printf("process:%d\n",i);
        unsigned long long sigStart = get_perf_count();

        memmove(eng1.mic_buffer, eng1.mic_buffer + DTLN_BLOCK_SHIFT, (DTLN_BLOCK_LEN - DTLN_BLOCK_SHIFT) * sizeof(float));
        memmove(eng1.lpb_buffer, eng1.lpb_buffer + DTLN_BLOCK_SHIFT, (DTLN_BLOCK_LEN - DTLN_BLOCK_SHIFT) * sizeof(float));

        for(int n=0;n<DTLN_BLOCK_SHIFT;n++){
            eng1.mic_buffer[n+DTLN_BLOCK_LEN-DTLN_BLOCK_SHIFT] = inputmicfile.samples[0][n+i*DTLN_BLOCK_SHIFT];
            eng1.lpb_buffer[n+DTLN_BLOCK_LEN-DTLN_BLOCK_SHIFT] = inputlpbfile.samples[0][n+i*DTLN_BLOCK_SHIFT];
        }

        tflite_infer(&eng1);

        unsigned long long sigEnd = get_perf_count();
        float msVal = (float)(sigEnd - sigStart)/1000000;
        printf("Run: %.2fms\n",msVal);

        for(int j=0;j<DTLN_BLOCK_SHIFT;j++){
            testaecdata.push_back(eng1.out_buffer[j]);    //for one forward process save first BLOCK_SHIFT model output samples
        }
    }
    printf("process end.save out\n");

    ExportWAV(argv[3],testaecdata,SAMEPLERATE);

    return 0;
}

// 简易short转浮点
static inline void short_to_float(const int16_t *input, float *output, size_t num_samples)
{
	for (size_t i = 0; i < num_samples; ++i)
	{
		output[i] = input[i] / 32768.0f;  // 将短整型值转换为浮点型 (范围: -1.0 到 1.0)
	}
}

// 简易浮点转short
static inline void float_to_short(const float *input, int16_t *output, size_t num_samples)
{
	for (size_t i = 0; i < num_samples; ++i)
	{
		// 确保浮点值在有效范围内
		if (input[i] < -1.0f)
		{
			output[i] = -32768;  // 下限
		}
		else if (input[i] > 1.0f)
		{
			output[i] = 32767;   // 上限
		}
		else
		{
			// 将浮点值映射到短整型范围
			output[i] = (int16_t)(input[i] * 32767);  // 转换
		}
	}
}

static trg_engine *g_peng = NULL;

void *dtln_create_handle(void)
{
    if(g_peng)
    {
        return (void*)g_peng;
    }
    g_peng = new trg_engine;
    tflite_create(g_peng);

    return (void*)g_peng;
}

int dtln_destroy_handle(void*phandle)
{
    if(g_peng)
    {
        return 0;
    }
    trg_engine *peng = (trg_engine*)phandle;

    delete peng;
    return 0;
}

int dtln_train_by_handle(void*phandle, short *pindata, short *pplbdata, int indatasize, short *poutdata)
{
    int retlen = 0;
    trg_engine *peng = (trg_engine*)phandle;

    if(peng)
    {
        memmove(peng->mic_buffer, peng->mic_buffer + DTLN_BLOCK_SHIFT, (DTLN_BLOCK_LEN - DTLN_BLOCK_SHIFT) * sizeof(float));
        memmove(peng->lpb_buffer, peng->lpb_buffer + DTLN_BLOCK_SHIFT, (DTLN_BLOCK_LEN - DTLN_BLOCK_SHIFT) * sizeof(float));

        short_to_float((short*)pindata, peng->mic_buffer+DTLN_BLOCK_SHIFT, indatasize/2);
        if(pplbdata)
        {
            short_to_float((short*)pplbdata, peng->lpb_buffer+DTLN_BLOCK_SHIFT, indatasize/2);
        }
        else
            memset(peng->lpb_buffer, 0, 512*sizeof(float));

        tflite_infer(peng);

        float_to_short(peng->out_buffer, (short*)poutdata, indatasize/2);

        retlen = indatasize;
    }
    else
    {
        memcpy(poutdata, pindata, indatasize);
    }
    return retlen;
}


static FILE *pfd_ao = NULL;

static FILE *pfd_ai = NULL;
static FILE *pfd_lpb = NULL;
static FILE *pfd_dtln = NULL;

static struct circlebuf ai_packet;
static pthread_mutex_t ai_mutex;

static struct circlebuf lpb_packet;
static pthread_mutex_t lpb_mutex;

static int AudioOutCb(char *DataBuffer, int DataSize, void *pContext)
{
    //printf("AudioOutCb DataSize:%d\n", DataSize);
    if(pfd_ao)
    {
        if(fread(DataBuffer, 1, DataSize, pfd_ao) != (size_t)DataSize)
        {
            //printf("AudioInCbFunc read fail\n");
            fseek(pfd_ao, 0, SEEK_SET);
        }

        pthread_mutex_lock(&lpb_mutex);
        circlebuf_push_back(&lpb_packet, DataBuffer, DataSize);
        pthread_mutex_unlock(&lpb_mutex);
    }

    return DataSize;
}

static int AudioInCb(char *DataBuffer, int DataSize, void *pContext)
{
    trg_engine *peng = (trg_engine*)pContext;
    if(peng)
    {
        if(pfd_ai)
            fwrite(DataBuffer, 1, DataSize, pfd_ai);

        // memmove(peng->mic_buffer, peng->mic_buffer + DTLN_BLOCK_SHIFT, (DTLN_BLOCK_LEN - DTLN_BLOCK_SHIFT) * sizeof(float));
        // memmove(peng->lpb_buffer, peng->lpb_buffer + DTLN_BLOCK_SHIFT, (DTLN_BLOCK_LEN - DTLN_BLOCK_SHIFT) * sizeof(float));

        // short_to_float((short*)DataBuffer, peng->mic_buffer+DTLN_BLOCK_SHIFT, DataSize/2);
        // memset(peng->lpb_buffer, 0, 512*sizeof(float));

        // tflite_infer(peng);

        // float_to_short(peng->out_buffer, (short*)DataBuffer, DataSize/2);
        char tmpbuf[1024] = {0};
#if 0
        dtln_train_by_handle(pContext, (short*)DataBuffer, NULL, DataSize, (short*)tmpbuf);
        if(pfd_dtln)
            fwrite(tmpbuf, 1, DataSize, pfd_dtln);
#else
        char tmplpbbuf[1024]={0};
        char tmpoutbuf[1024]={0};
        circlebuf_push_back(&ai_packet, DataBuffer, DataSize);
        #define DTLN_NEED_LEN    512
        while (ai_packet.size >= DTLN_NEED_LEN)
        {
            circlebuf_pop_front(&ai_packet, tmpbuf, DTLN_NEED_LEN);

            pthread_mutex_lock(&lpb_mutex);
            if(lpb_packet.size >= DTLN_NEED_LEN)
            {
                memset(tmplpbbuf, 0, sizeof(tmplpbbuf));
                circlebuf_pop_front(&lpb_packet, tmplpbbuf, DTLN_NEED_LEN);
            }
            pthread_mutex_unlock(&lpb_mutex);

            dtln_train_by_handle(pContext, (short *)tmpbuf, (short *)tmplpbbuf, DTLN_NEED_LEN, (short *)tmpoutbuf);
            //circlebuf_push_back(&pmgnt_audio->record_packet, tmpoutbuf, DTLN_NEED_LEN);
            if(pfd_dtln)
            {
                fwrite(tmpoutbuf, 1, DTLN_NEED_LEN, pfd_dtln);
            }
            if(pfd_lpb)
            {
                fwrite(tmplpbbuf, 1, DTLN_NEED_LEN, pfd_lpb);
            }
        }
#endif
    }
    return DataSize;
}

